      typeof key === "symbol" ||
      hasAccessorDescriptor(descriptor) ||
      hasCallableDescriptor(descriptor) ||
      isSchemaMissingValueDescriptor(key, trail, descriptor.value)
    ) {
      continue;
    }

    scanNestedSafety(
      descriptor.value,
      [...trail, normalizeFieldName(key)],
      reasons,
      context,
      schemaState,
      seen,
